// TestExecute_ExplicitHarnessEmptyModelWithPolicy_RoutesWithinHarness asserts
// AC4 from ddx-1e516bc9: when Harness is pinned and Model is empty but a
// routing policy is provided, the routing engine runs within the harness's
// eligible models (not the old silent-empty-model path).

package routing

import (
	"fmt"
	"sort"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/modelcatalog"
)

// Request is the routing input. All fields are optional except at least
// one of {Policy, Model, Harness, Provider} should be set (otherwise the
// engine has nothing to disambiguate on).
//
// Provider is present from day one (fixes ddx-8610020e — no soft-preference
// dropping).
type Request struct {
	Policy             string // "cheap" | "default" | "smart" | "air-gapped"
	Model              string // exact concrete model pin
	Provider           string // exact provider pin; constrains routing to one provider identity
	Harness            string // hard preference; constrains routing to one harness
	Reasoning          string // public reasoning scalar
	Permissions        string // "safe" | "supervised" | "unrestricted"
	ProviderPreference string // "local-first" | "subscription-first" | "local-only" | "subscription-only"
	CorrelationID      string // validated sticky route key, when available
	AllowLocal         bool
	Require            []string

	// EstimatedPromptTokens, when > 0, drives context-window gating.
	EstimatedPromptTokens int

	// RequiresTools, when true, requires the candidate to support tool calling.
	RequiresTools bool
	MinPower      int
	MaxPower      int

	// ExcludedRoutes lists caller-supplied (Provider, Model, Endpoint)
	// combinations to skip during candidate selection. The engine marks
	// matching candidates ineligible with FilterReasonCallerExcluded.
	ExcludedRoutes []ExcludedRoute
}

// ExcludedRoute is a caller-supplied exclusion hint for the routing engine.
// Provider is required; Model and Endpoint are optional (empty matches any).
type ExcludedRoute struct {
	Provider string
	Model    string // optional; empty matches any model on the provider
	Endpoint string // optional; empty matches any endpoint
}

const (
	ProviderPreferenceLocalFirst        = "local-first"
	ProviderPreferenceSubscriptionFirst = "subscription-first"
	ProviderPreferenceLocalOnly         = "local-only"
	ProviderPreferenceSubscriptionOnly  = "subscription-only"

	ContextSourceProviderAPI    = "provider_api"
	ContextSourceProviderConfig = "provider_config"
	ContextSourceCatalog        = "catalog"
	ContextSourceDefault        = "default"
	ContextSourceUnknown        = "unknown"
)

// MinContextWindow returns the minimum context window the request requires,
// derived from EstimatedPromptTokens with a safety margin.
func (r Request) MinContextWindow() int {
	if r.EstimatedPromptTokens <= 0 {
		return 0
	}
	// 1.25x safety margin for response tokens + tool overhead.
	return r.EstimatedPromptTokens + r.EstimatedPromptTokens/4
}

const (
	QuotaTrendUnknown    = "unknown"
	QuotaTrendHealthy    = "healthy"
	QuotaTrendBurning    = "burning"
	QuotaTrendExhausting = "exhausting"
)

// HarnessEntry is the harness-side input the caller (service) supplies.
// It is the routing engine's view of a registered harness; the engine does
// not import the harnesses package directly to keep the dependency narrow.
type HarnessEntry struct {
	Name                string
	Surface             string
	CostClass           string
	IsLocal             bool
	IsSubscription      bool
	IsHTTPProvider      bool
	AutoRoutingEligible bool
	TestOnly            bool
	ExactPinSupport     bool
	DefaultModel        string
	SupportedModels     []string
	SupportedReasoning  []string
	MaxReasoningTokens  int
	SupportedPerms      []string
	SupportsTools       bool

	// Available reflects the harness's discovered availability.
	Available bool

	// QuotaOK / QuotaPercentUsed reflect live quota state (when applicable).
	// SubscriptionOK gates subscription harnesses at the eligibility level:
	// when false, the candidate is ineligible regardless of score.
	QuotaOK          bool
	QuotaPercentUsed int
	QuotaStale       bool
	QuotaTrend       string // unknown|healthy|burning|exhausting
	QuotaReason      string
	SubscriptionOK   bool // false = hard gate; true = score-based demotion

	// InCooldown marks the entire harness as being in a failure cooldown.
	// When true the harness is demoted in score (via candidateInternal.InCooldown)
	// but not hard-rejected, so it can still win when all other harnesses are
	// also unavailable.
	InCooldown bool

	// Providers is the list of providers this harness can dispatch to.
	// For subprocess harnesses (claude/codex) this is typically a single
	// vendor entry. For the native "fiz" harness it is the configured
	// list of HTTP providers.
	Providers []ProviderEntry
}

// ProviderEntry describes one provider available under a harness.
type ProviderEntry struct {
	Name                 string
	BaseURL              string
	ServerInstance       string
	EndpointName         string
	EndpointBaseURL      string
	DefaultModel         string
	Billing              modelcatalog.BillingModel
	CostClass            string
	DiscoveredIDs        []string // models discovered via /v1/models or equivalent
	DiscoveryAttempted   bool
	ContextWindows       map[string]int
	ContextWindowSources map[string]string
	ContextWindow        int
	ContextWindowSource  string
	SupportsTools        bool

	// CostUSDPer1kTokens is the estimated blended USD cost per 1,000 tokens.
	// A zero value with CostSourceUnknown means the provider cost is unknown.
	CostUSDPer1kTokens float64
	// CostSource describes where CostUSDPer1kTokens came from: catalog,
	// subscription, user-config, or unknown.
	CostSource string
	// ActualCashSpend marks providers that would consume metered spend when
	// selected.
	ActualCashSpend bool

	// InCooldown reflects whether this provider is in a failure-cooldown window.
	InCooldown bool

	// ExcludeFromDefaultRouting, when true, prevents this provider from being
	// selected during unpinned automatic routing. An explicit provider, harness,
	// or model pin bypasses this gate so the operator can still reach the
	// provider intentionally. Corresponds to IncludeByDefault=false in config.
	ExcludeFromDefaultRouting bool
}

const (
	// CostSourceCatalog means cost came from the model catalog.
	CostSourceCatalog = "catalog"
	// CostSourceSubscription means cost came from subscription quota pricing.
	CostSourceSubscription = "subscription"
	// CostSourceUnknown means no reliable cost estimate is available.
	CostSourceUnknown = "unknown"
	// CostSourceUserConfig means cost came from explicit user configuration.
	CostSourceUserConfig = "user-config"
)

// Decision is the routing engine's output: the picked candidate plus the
// full ranked list (including rejected ones with rejection reasons).
type Decision struct {
	Harness        string
	Provider       string
	Endpoint       string
	ServerInstance string
	Model          string
	Reason         string
	Candidates     []Candidate
}

// Candidate is one ranked routing option.
type Candidate struct {
	Harness            string
	Provider           string
	Billing            modelcatalog.BillingModel
	Endpoint           string
	ServerInstance     string
	Model              string
	Score              float64
	CostUSDPer1kTokens float64
	CostSource         string
	ActualCashSpend    bool
	Power              int
	ContextLength      int
	ContextSource      string
	ScoreComponents    map[string]float64
	Eligible           bool
	Reason             string

	// FilterReason is the typed disqualification category, set at the
	// rejection site that decided why this candidate is ineligible.
	// Empty for eligible candidates. Service-layer code maps this to the
	// public FilterReason* string constants without parsing free-form
	// Reason text.
	FilterReason FilterReason

	// LatencyMS, SuccessRate, and CostClass expose the score-component
	// inputs so callers can render per-axis explanations alongside the
	// final Score. Zero / negative values mean unknown (see Inputs docs).
	LatencyMS       float64
	SuccessRate     float64
	CostClass       string
	SpeedTPS        float64
	Utilization     float64
	ContextHeadroom int

	QuotaOK          bool
	QuotaPercentUsed int
	QuotaTrend       string
	StickyAffinity   float64
}

// FilterReason categorizes why a routing candidate was disqualified.
// The zero value (empty string) means the candidate is eligible.
type FilterReason string

const (
	// FilterReasonEligible is the zero value for an eligible candidate.
	FilterReasonEligible FilterReason = ""
	// FilterReasonContextTooSmall: candidate's context window is below the
	// request's MinContextWindow().
	FilterReasonContextTooSmall FilterReason = "context_too_small"
	// FilterReasonNoToolSupport: request needs tool calling but candidate
	// does not support it.
	FilterReasonNoToolSupport FilterReason = "no_tool_support"
	// FilterReasonReasoningUnsupported: candidate cannot satisfy the
	// requested reasoning policy.
	FilterReasonReasoningUnsupported FilterReason = "reasoning_unsupported"
	// FilterReasonUnhealthy: harness/provider is unavailable, in cooldown,
	// out of quota, or excluded by a hard provider-preference gate.
	FilterReasonUnhealthy FilterReason = "unhealthy"
	// FilterReasonScoredBelowTop: catch-all for ineligibility that does
	// not fit a more specific category (also used for capability
	// mismatches such as permissions/model-pin/exact-pin and for model
	// resolution failures).
	FilterReasonScoredBelowTop FilterReason = "scored_below_top"
	// FilterReasonPinMismatch: candidate was rejected because it does not
	// satisfy an explicit caller pin such as Provider.
	FilterReasonPinMismatch FilterReason = "pin_mismatch"
	// FilterReasonPowerMissing: automatic routing requires catalog power
	// metadata, but the candidate model is unknown or has zero power.
	FilterReasonPowerMissing FilterReason = "power_missing"

package fizeau

import (
	"context"
	"errors"
	"fmt"
	"sort"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/compaction"
	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/modelcatalog"
	"github.com/easel/fizeau/internal/modeleligibility"
	"github.com/easel/fizeau/internal/modelsnapshot"
	"github.com/easel/fizeau/internal/provider/utilization"
	"github.com/easel/fizeau/internal/routing"
	"github.com/easel/fizeau/internal/serverinstance"
)

var loadRoutingCatalog = modelcatalog.Default

// ResolveRoute resolves an under-specified RouteRequest to a concrete
// (Harness, Provider, Model) decision per CONTRACT-003.
//
// The implementation delegates to internal/routing.Resolve — the single
// routing engine that consolidates DDx-side harness-tier ranking and
// fiz-side provider failover ordering.
func (s *service) ResolveRoute(ctx context.Context, req RouteRequest) (*RouteDecision, error) {
	if err := ValidatePowerBounds(req.MinPower, req.MaxPower); err != nil {
		return nil, err
	}
	if err := ValidateRole(req.Role); err != nil {
		return nil, err
	}
	if err := ValidateCorrelationID(req.CorrelationID); err != nil {
		return nil, err
	}
	if req.Harness != "" && req.Model != "" {
		canonical := harnesses.ResolveHarnessAlias(req.Harness)
		if !s.registry.Has(canonical) {
			return nil, fmt.Errorf("unknown harness %q", req.Harness)
		}
		cfg, _ := s.registry.Get(canonical)
		if err := validateExplicitHarnessModel(canonical, cfg, req.Model, req.Provider); err != nil {
			return nil, err
		}
	}
	if req.Harness != "" && req.Policy != "" {
		canonical := harnesses.ResolveHarnessAlias(req.Harness)
		if !s.registry.Has(canonical) {
			return nil, fmt.Errorf("unknown harness %q", req.Harness)
		}
		cfg, _ := s.registry.Get(canonical)
		if err := validateExplicitHarnessPolicy(canonical, cfg, req.Policy); err != nil {
			return nil, err
		}
	}
	cat := serviceRoutingCatalog()
	requestedPolicy := req.Policy
	policy := routingPolicyForName(cat, requestedPolicy)
	powerPolicy := routePowerPolicyForRequest(cat, req)
	providerPreference, err := providerPreferenceForPolicy(cat, requestedPolicy)
	if err != nil {
		return &RouteDecision{
			RequestedPolicy: req.Policy,
			PowerPolicy:     powerPolicy,
		}, err
	}
	in, snapshot := s.buildRoutingInputsWithCatalog(ctx, cat, modelsnapshot.RefreshIfStale)

	resolvedModel, modelCandidates, modelErr := s.resolveModelConstraint(req.Harness, req.Provider, req.Model, in, cat)
	if modelErr != nil {
		result := &RouteDecision{
			RequestedPolicy: req.Policy,
			PowerPolicy:     powerPolicy,
			Candidates:      modelCandidates,
		}
		s.annotateRouteDecisionEvidence(result)
		return result, publicRoutingError(modelErr, result.Candidates, req.Policy)
	}

	rReq := routing.Request{
		Policy:                policy,
		Model:                 resolvedModel,
		Provider:              req.Provider,
		Harness:               req.Harness,
		Reasoning:             effectiveReasoningString(req.Reasoning),
		Permissions:           req.Permissions,
		ProviderPreference:    providerPreference,
		EstimatedPromptTokens: req.EstimatedPromptTokens,
		RequiresTools:         req.RequiresTools,
		CorrelationID:         req.CorrelationID,
		AllowLocal:            req.AllowLocal,
		Require:               append([]string(nil), req.Require...),
		ExcludedRoutes:        publicToRoutingExcludedRoutes(req.ExcludedRoutes),
	}
	if policyEntry, _, ok := policyForName(cat, requestedPolicy); ok {
		rReq.AllowLocal = rReq.AllowLocal || policyEntry.AllowLocal
		rReq.Require = append(append([]string(nil), policyEntry.Require...), rReq.Require...)
	}
	rReq.MinPower, rReq.MaxPower = routePowerBoundsForRequest(req, powerPolicy)
	s.applyRouteAttemptCooldowns(&in)
	dec, err := routing.Resolve(rReq, in)
	if err != nil {
		if escalated, edec, eerr := escalatePolicyLadder(rReq, in, err, req.Policy); escalated {
			dec = edec
			err = eerr
		}
	}
	result := routeDecisionFromInternal(dec, powerPolicy)
	if err != nil {
		if result == nil {
			result = &RouteDecision{}
		}
		result.RequestedPolicy = req.Policy
		result.PowerPolicy = powerPolicy
		s.annotateRouteDecisionEvidence(result)
		return result, publicRoutingError(err, result.Candidates, req.Policy)
	}
	s.applyStickyRouteLease(req.CorrelationID, result)
	if result != nil && result.Endpoint == "" {
		_, endpoint, _ := splitEndpointProviderRef(result.Provider)
		result.Endpoint = endpoint
	}
	s.annotateRouteDecisionSnapshotEvidence(result, snapshot)
	s.annotateRouteDecisionEvidence(result)
	// Cache the decision so RouteStatus can surface LastDecision.
	if result != nil {
		result.RequestedPolicy = req.Policy
		result.PowerPolicy = powerPolicy
		result.Model = resolveSubprocessModelAlias(result.Harness, result.Model)
		result.Power = catalogPowerForModel(cat, result.Model)
	}
	s.cacheRouteDecision(req.Model, result)
	return result, nil
}

func routeDecisionFromInternal(dec *routing.Decision, powerPolicy RoutePowerPolicy) *RouteDecision {
	if dec == nil {
		return nil
	}
	return &RouteDecision{
		Harness:        dec.Harness,
		Provider:       dec.Provider,
		Endpoint:       dec.Endpoint,
		ServerInstance: dec.ServerInstance,
		Model:          dec.Model,
		Reason:         dec.Reason,
		Candidates:     routeCandidatesFromInternal(dec.Candidates, powerPolicy),
	}
}

func routeCandidatesFromInternal(candidates []routing.Candidate, powerPolicy RoutePowerPolicy) []RouteCandidate {
	if len(candidates) == 0 {
		return nil
	}
	out := make([]RouteCandidate, len(candidates))
	for i, candidate := range candidates {
		out[i] = routeCandidateFromInternal(candidate, powerPolicy)
	}
	return out
}

func routeCandidateFromInternal(candidate routing.Candidate, powerPolicy RoutePowerPolicy) RouteCandidate {
	components := RouteCandidateComponents{
		Power:            candidate.Power,
		Cost:             candidate.CostUSDPer1kTokens,
		CostClass:        candidate.CostClass,
		LatencyMS:        candidate.LatencyMS,
		SpeedTPS:         candidate.SpeedTPS,
		Utilization:      candidate.Utilization,
		SuccessRate:      candidate.SuccessRate,
		QuotaOK:          candidate.QuotaOK,
		QuotaPercentUsed: candidate.QuotaPercentUsed,
		QuotaTrend:       candidate.QuotaTrend,
		Capability:       capabilityScoreForCostClass(candidate.CostClass),
		ContextHeadroom:  candidate.ContextHeadroom,
		StickyAffinity:   candidate.StickyAffinity,
	}
	powerHintFit := scorePowerHintFit(candidate.Power, powerPolicy)
	scorePower := candidate.ScoreComponents["power"]
	scoreCost := candidate.ScoreComponents["cost"]
	scorePerformance := candidate.ScoreComponents["performance"]
	scoreLocality := candidate.ScoreComponents["deployment_locality"]
	scoreQuota := candidate.ScoreComponents["quota_health"]
	scoreUtilization := candidate.ScoreComponents["utilization"]
	components.PowerHintFit = powerHintFit
	components.PowerWeightedCapability = scorePower - powerHintFit + positiveScorePart(scoreCost)
	components.LatencyWeight = positiveScorePart(scorePerformance)
	components.StaleSignalPenalty = positiveScorePart(-scorePerformance)
	components.PlacementBonus = scoreLocality + candidate.StickyAffinity
	components.QuotaBonus = positiveScorePart(scoreQuota)
	components.MarginalCostPenalty = positiveScorePart(-scoreCost)
	components.AvailabilityPenalty = positiveScorePart(-scoreQuota) + positiveScorePart(-scoreUtilization)
	return RouteCandidate{
		Harness:             candidate.Harness,
		Provider:            candidate.Provider,
		Billing:             candidate.Billing,
		ActualCashSpend:     candidate.ActualCashSpend,
		Endpoint:            candidate.Endpoint,
		ServerInstance:      candidate.ServerInstance,
		Model:               candidate.Model,
		Score:               candidate.Score,
		CostUSDPer1kTokens:  candidate.CostUSDPer1kTokens,
		CostSource:          candidate.CostSource,
		EffectiveCost:       candidate.CostUSDPer1kTokens,
		EffectiveCostSource: candidate.CostSource,
		Eligible:            candidate.Eligible,
		Reason:              candidate.Reason,
		FilterReason:        publicFilterReason(candidate),
		ContextLength:       candidate.ContextLength,
		ContextSource:       candidate.ContextSource,
		Components:          components,
	}
}

func scorePowerHintFit(power int, policy RoutePowerPolicy) float64 {
	if power <= 0 {
		return 0
	}
	if policy.MinPower > 0 && power < policy.MinPower {
		// Mirror the engine scorer: materially underpowered routes should not
		// win just because they are cheap.
		return -float64(policy.MinPower-power) * 12
	}
	if policy.MaxPower > 0 && power > policy.MaxPower {
		return -float64(power - policy.MaxPower)
	}
	return 0
}

func positiveScorePart(v float64) float64 {
	if v > 0 {
		return v
	}
	return 0
}

