package fizeau

// This file implements ListModels for the FizeauService service.
// It lives in the root package to avoid import cycles; provider and catalog
// data is injected via ServiceConfig (defined in service.go).
//
// Provider-backed models are assembled from the unified model snapshot used by
// the CLI model inventory path. Codex and Claude expose a separate
// harness-native surface backed by PTY/CLI evidence.

import (
	"context"
	"fmt"
	"net/url"
	"strings"

	"github.com/easel/fizeau/internal/compaction"
	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/harnesses/builtin"
	"github.com/easel/fizeau/internal/modelcatalog"
	"github.com/easel/fizeau/internal/modelsnapshot"
	"github.com/easel/fizeau/internal/provider/lmstudio"
	"github.com/easel/fizeau/internal/provider/omlx"
	"github.com/easel/fizeau/internal/provider/openrouter"
	"github.com/easel/fizeau/internal/serverinstance"
)

// ListModels returns models matching the filter, with full metadata.
// Empty filter returns all models from every reachable provider.
func (s *service) ListModels(ctx context.Context, filter ModelFilter) ([]ModelInfo, error) {
	if filter.Harness != "" && harnesses.ResolveHarnessAlias(filter.Harness) != "fiz" {
		return s.listModelsForSubprocessHarness(filter), nil
	}

	sc := s.opts.ServiceConfig
	if sc == nil {
		return nil, fmt.Errorf("service: no ServiceConfig provided; pass ServiceOptions.ServiceConfig")
	}

	// Load the model catalog once for cross-referencing.
	cat, _ := modelcatalog.Default() // ignore error: catalog miss is non-fatal
	cacheRoot, err := serviceSnapshotCacheRoot()
	if err != nil {
		return nil, err
	}
	snapshot, err := assembleModelSnapshotFromServiceConfigWithOptions(ctx, sc, cat, cacheRoot, modelsnapshot.AssembleOptions{Refresh: modelsnapshot.RefreshForce})
	if err != nil {
		return nil, err
	}
	return s.listModelsFromSnapshot(ctx, sc, cat, snapshot, filter), nil
}

func (s *service) listModelsForSubprocessHarness(filter ModelFilter) []ModelInfo {
	name := harnesses.ResolveHarnessAlias(filter.Harness)
	cfg, ok := s.registry.Get(name)
	modelIDs := subprocessHarnessModelIDs(name, cfg)
	if !ok || harnessRunsInProcessOrHTTP(cfg) || len(modelIDs) == 0 {
		return nil
	}
	if filter.Provider != "" && filter.Provider != name {
		return nil
	}
	cat, _ := modelcatalog.Default()
	out := make([]ModelInfo, 0, len(modelIDs))
	for i, id := range modelIDs {
		info := ModelInfo{
			ID:             id,
			Provider:       name,
			Harness:        name,
			EndpointName:   name,
			ServerInstance: name,
			Capabilities:   []string{"streaming", "tool_use"},
			Available:      true,
			IsDefault:      cfg.DefaultModel != "" && id == cfg.DefaultModel,
			Billing:        harnessPaymentKind(name, cfg),
			RankPosition:   i,
		}
		if cat != nil {
			info.ContextLength, info.ContextSource = resolveContextEvidence(context.Background(), ServiceProviderEntry{}, id, cat)
			info.Cost, info.PerfSignal = catalogCostAndPerf(cat, id)
			info.Power, info.AutoRoutable, info.ExactPinOnly = catalogPowerEligibility(cat, id)
		}
		info.Utilization = s.routeUtilizationEvidence(name, info.ServerInstance, info.EndpointName, id)
		out = append(out, info)
	}
	return out
}

func subprocessHarnessModelIDs(name string, cfg harnesses.HarnessConfig) []string {
	models := append([]string(nil), cfg.Models...)
	mdh, ok := builtin.New(name).(harnesses.ModelDiscoveryHarness)
	if !ok {
		return models
	}
	snapshot := mdh.DefaultModelSnapshot()
	models = appendUniqueModelIDs(models, snapshot.Models...)
	for _, family := range mdh.SupportedAliases() {
		resolved, err := mdh.ResolveModelAlias(family, snapshot)
		if err == nil && resolved != family {
			models = appendUniqueModelIDs(models, resolved)
		}
	}
	return models
}

func resolveSubprocessModelAlias(harness, model string) string {
	switch harness {
	case "claude":
		return claudeCLIExecutableModel(model)
	default:
		mdh, ok := builtin.New(harness).(harnesses.ModelDiscoveryHarness)
		if !ok {
			return model
		}
		resolved, err := mdh.ResolveModelAlias(model, mdh.DefaultModelSnapshot())
		if err != nil {
			return model
		}
		return resolved
	}
}

func claudeCLIExecutableModel(model string) string {
	normalized := strings.ToLower(strings.TrimSpace(model))
	switch {
	case normalized == "sonnet" || strings.HasPrefix(normalized, "sonnet-") || strings.HasPrefix(normalized, "claude-sonnet-"):
		return "sonnet"
	case normalized == "opus" || strings.HasPrefix(normalized, "opus-") || strings.HasPrefix(normalized, "claude-opus-"):
		return "opus"
	case normalized == "haiku" || strings.HasPrefix(normalized, "haiku-") || strings.HasPrefix(normalized, "claude-haiku-"):
		return "haiku"
	default:
		return model
	}
}

func appendUniqueModelIDs(values []string, additions ...string) []string {
	for _, value := range additions {
		value = strings.TrimSpace(value)
		if value == "" {
			continue
		}
		found := false
		for _, existing := range values {
			if existing == value {
				found = true
				break
			}
		}
		if !found {
			values = append(values, value)
		}
	}
	return values
}

func (s *service) listModelsFromSnapshot(ctx context.Context, sc ServiceConfig, cat *modelcatalog.Catalog, snapshot modelsnapshot.ModelSnapshot, filter ModelFilter) []ModelInfo {
	defaultProviderName := sc.DefaultProviderName()
	entries := make(map[string]ServiceProviderEntry, len(sc.ProviderNames()))
	for _, name := range sc.ProviderNames() {
		if filter.Provider != "" && filter.Provider != name {
			continue
		}
		entry, ok := sc.Provider(name)
		if !ok {
			continue
		}
		entries[name] = entry
	}

	modelsByProvider := make(map[string][]modelsnapshot.KnownModel, len(snapshot.Models))
	for _, model := range snapshot.Models {
		if filter.Provider != "" && filter.Provider != model.Provider {
			continue
		}
		if _, ok := entries[model.Provider]; !ok {
			continue
		}
		modelsByProvider[model.Provider] = append(modelsByProvider[model.Provider], model)
	}

package serviceimpl

import (
	"context"
	"encoding/json"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/reasoning"
)

// SubprocessRequest is the API-neutral request data needed by subprocess
// harness runner implementations.
type SubprocessRequest struct {
	Prompt         string
	SystemPrompt   string
	WorkDir        string
	Permissions    string
	Temperature    *float32
	Seed           *int64
	Reasoning      reasoning.Reasoning
	Timeout        time.Duration
	IdleTimeout    time.Duration
	SessionLogDir  string
	Metadata       map[string]string
	Decision       ExecuteRunnerDecision
	Started        time.Time
	SessionLogPath string
}

// SubprocessCallbacks bridge service-owned event/progress/session-log behavior
// without importing root public service types.
type SubprocessCallbacks struct {
	BeforeExecute func()
	BeforeFinal   func(harnesses.FinalData)
	ObserveEvent  func(harnesses.Event) harnesses.Event
	EmitEvent     func(harnesses.Event) bool
	Finalize      func(harnesses.FinalData)
	WriteEnd      func(map[string]string, harnesses.FinalData)
}

// RunSubprocess executes a subprocess harness and forwards its event stream.
func RunSubprocess(ctx context.Context, req SubprocessRequest, runner harnesses.Harness, cb SubprocessCallbacks) {
	hReq := harnesses.ExecuteRequest{
		Prompt:        req.Prompt,
		SystemPrompt:  req.SystemPrompt,
		Provider:      req.Decision.Provider,
		Model:         req.Decision.Model,
		WorkDir:       req.WorkDir,
		Permissions:   req.Permissions,
		Temperature:   subprocessTemperature(req.Temperature),
		Seed:          subprocessSeed(req.Seed),
		Reasoning:     adapterReasoning(req.Reasoning),
		Timeout:       req.Timeout,
		IdleTimeout:   req.IdleTimeout,
		SessionLogDir: req.SessionLogDir,
		Metadata:      req.Metadata,
	}
	if cb.BeforeExecute != nil {
		cb.BeforeExecute()
	}
	in, err := runner.Execute(ctx, hReq)
	if err != nil {
		finalizeSubprocess(cb, harnesses.FinalData{
			Status:     "failed",
			Error:      err.Error(),
			DurationMS: time.Since(req.Started).Milliseconds(),
			RoutingActual: &harnesses.RoutingActual{
				Harness:        req.Decision.Harness,
				Provider:       req.Decision.Provider,
				ServerInstance: req.Decision.ServerInstance,
				Model:          req.Decision.Model,
			},
		})
		return
	}
	for ev := range in {
		if ev.Metadata == nil {
			ev.Metadata = req.Metadata
		}
		if ev.Type == harnesses.EventTypeFinal {
			var final harnesses.FinalData
			if err := json.Unmarshal(ev.Data, &final); err == nil && cb.BeforeFinal != nil {
				cb.BeforeFinal(final)
			}
			ev = stampSubprocessFinalRouting(ev, req.Decision)
			ev = stampSubprocessFinalSessionLog(ev, req.SessionLogPath)
			if err := json.Unmarshal(ev.Data, &final); err == nil && cb.WriteEnd != nil {
				cb.WriteEnd(req.Metadata, final)
			}
		}
		if cb.ObserveEvent != nil {
			ev = cb.ObserveEvent(ev)
		}
		if cb.EmitEvent != nil && !cb.EmitEvent(ev) {
			return
		}
	}
}

func subprocessTemperature(v *float32) float32 {
	if v == nil {
		return 0
	}
	return *v
}

func subprocessSeed(v *int64) int64 {
	if v == nil {
		return 0
	}
	return *v
}

func adapterReasoning(value reasoning.Reasoning) string {
	policy, err := reasoning.ParseString(string(value))
	if err != nil {
		return string(value)
	}
	switch policy.Kind {
	case reasoning.KindUnset, reasoning.KindAuto, reasoning.KindOff:
		return ""
	case reasoning.KindTokens:
		if policy.Tokens == 0 {
			return ""
		}
		return string(policy.Value)
	case reasoning.KindNamed:
		return string(policy.Value)
	default:
		return string(value)
	}
}

func stampSubprocessFinalSessionLog(ev harnesses.Event, sessionLogPath string) harnesses.Event {
	if sessionLogPath == "" {
		return ev
	}
	var final harnesses.FinalData
	if err := json.Unmarshal(ev.Data, &final); err != nil {
		return ev
	}
	final.SessionLogPath = sessionLogPath
	raw, err := json.Marshal(final)
	if err != nil {
		return ev
	}
	ev.Data = raw
	return ev
}

func stampSubprocessFinalRouting(ev harnesses.Event, decision ExecuteRunnerDecision) harnesses.Event {
	var final harnesses.FinalData
	if err := json.Unmarshal(ev.Data, &final); err != nil {
		return ev
	}
	if final.RoutingActual == nil {
		final.RoutingActual = &harnesses.RoutingActual{
			Harness:        decision.Harness,
			Provider:       decision.Provider,
			ServerInstance: decision.ServerInstance,
			Model:          decision.Model,
		}
	}
	raw, err := json.Marshal(final)
	if err != nil {
		return ev
	}
	ev.Data = raw
	return ev
}

func finalizeSubprocess(cb SubprocessCallbacks, final harnesses.FinalData) {
	if cb.Finalize != nil {
		cb.Finalize(final)
	}
}

